class BaseStorageDriver {
  _loadedTimes = 0;
  _destroyed = false;
  _log;
  _platform;
  setup(log, platform) {
    this._log = log.create("sqlite");
    this._platform = platform;
  }
  get loaded() {
    return this._loadedTimes > 0;
  }
  async load() {
    if (this._loadedTimes === 0) {
      await this._load();
      this._destroyed = false;
    }
    this._loadedTimes++;
  }
  async destroy() {
    if (this._destroyed) {
      return;
    }
    this._loadedTimes--;
    if (this._loadedTimes === 0) {
      await this._destroy();
      this._destroyed = true;
    }
  }
  save() {
    return this._save?.();
  }
}
export {
  BaseStorageDriver
};
